(globalThis["webpackChunkquasar_tufte"]=globalThis["webpackChunkquasar_tufte"]||[]).push([[618],{3618:(e,a,n)=>{"use strict";n.r(a),n.d(a,{default:()=>Se});var i=n(9835),t=n(9652),o=n.n(t);const r={class:"tufte-body"},s=(0,i._)("h1",{id:"tufte-css"},"Silvina Caino-Lores",-1),l=(0,i._)("img",{src:o(),alt:""},null,-1),c=(0,i._)("br",null,null,-1),d=(0,i._)("b",null,"Research Assistant Professor",-1),u=(0,i.Uk)(","),h=(0,i._)("br",null,null,-1),p=(0,i.Uk)(" Department of Electrical Engineering and Computer Science, Global Computing Laboratory, "),m=(0,i._)("a",{href:"https://www.eecs.utk.edu/people/silvina-caino-lores/"},"University of Tennessee Knoxville",-1),g=(0,i._)("br",null,null,-1),f=(0,i._)("br",null,null,-1),y=(0,i.Uk)(" scaino-lores@acm.org"),b=(0,i._)("br",null,null,-1),w={style:{display:"inline-block"}},v=(0,i.Uk)(),C=(0,i._)("a",{href:"https://orcid.org/0000-0002-6922-0138"},"0000-0002-6922-0138",-1),k=(0,i._)("br",null,null,-1),S={style:{display:"inline-block"}},A=(0,i.Uk)(),P=(0,i._)("a",{href:"https://scholar.google.es/citations?user=XmoKuRwAAAAJ&hl=en"},"Google Scholar",-1),T=(0,i.Uk)("   "),N=(0,i.Uk)(" Research Assistant Professor"),D=(0,i._)("br",null,null,-1),x=(0,i.Uk)(" Department of Electrical Engineering and Computer Science"),E=(0,i._)("br",null,null,-1),M=(0,i.Uk)(" Global Computing Laboratory "),I=(0,i._)("br",null,null,-1),H=(0,i.Uk)(" scaino-lores@acm.org   "),L=(0,i.Uk)(" scainolo@utk.edu"),R=(0,i._)("br",null,null,-1),B=(0,i._)("a",{href:"https://www.eecs.utk.edu/people/silvina-caino-lores/"},"University of Tennessee Knoxville",-1),_=(0,i._)("br",null,null,-1),W={style:{display:"inline-block"}},G=(0,i.Uk)(),z=(0,i._)("a",{href:"https://orcid.org/0000-0002-6922-0138"},"0000-0002-6922-0138",-1),F=(0,i.Uk)("   "),j={style:{display:"inline-block"}},J=(0,i.Uk)(),U=(0,i._)("a",{href:"https://scholar.google.es/citations?user=XmoKuRwAAAAJ&hl=en"},"Google Scholar",-1),K=(0,i.Uk)("   "),q=(0,i.uE)('<section style=""><h2 id="biography" class="no-count">Biography</h2><p> Silvina Caino-Lores is a Research Assistant Professor at the University of Tennessee, Knoxville, as a member of the Global Computing Laboratory directed by Dr. Michela Taufer. She obtained her PhD in Computer Science and Technology from Carlos III University of Madrid (Spain) in 2019. She earned her BSc and MSc in Computer Science and Technology from the same University in 2014 and 2015, respectively. Dr. Caino-Lores received the Spanish Society for Computer Science (SCIE)-BBVA Foundation Young Researcher in Computer Science Award in 2020. Her research interests include cloud computing, in-memory computing and storage, HPC scientific simulations, and data-centric paradigms. Her recent works and collaborations focus on the area of convergence between HPC and Big Data analytics at the application and platform layers. </p></section><section style=""><h2 id="research" class="no-count">Research Interests</h2><p> My research interests include HPC/Cloud convergence, high-performance storage, holistic performance engineering for scientific workflows, machine learning applications in instrumentation and optimization of distributed systems. </p><ul><li>Scientific Workflows</li><li>High-Performance Computing (HPC)</li><li>High-Performance Storage Systems</li><li>HPC/Cloud Convergence</li><li>Computing Continuum</li></ul></section>',2),O=(0,i._)("h2",{id:"publications",class:"no-count"},"Publications",-1),X=(0,i._)("h3",{id:"pubs-journals",class:"no-count"},"Journals",-1),Z={class:"fullwidth"},Y=(0,i._)("h3",{id:"pubs-",class:"no-count"},"International Conferences",-1),V={class:"fullwidth"},Q=(0,i._)("h3",{id:"pubs-",class:"no-count"},"Workshops",-1),$={class:"fullwidth"},ee=(0,i._)("h3",{id:"pubs-",class:"no-count"},"Posters and Short Papers",-1),ae={class:"fullwidth"},ne=(0,i._)("h3",{id:"pubs-",class:"no-count"},"National Conferences",-1),ie={class:"fullwidth"},te=(0,i._)("h3",{id:"pubs-",class:"no-count"},"Reports",-1),oe={class:"fullwidth"},re=(0,i._)("h3",{id:"pubs-",class:"no-count"},"Preprints",-1),se={class:"fullwidth"};function le(e,a,n,t,o,le){const ce=(0,i.up)("q-icon"),de=(0,i.up)("t-marginnote"),ue=(0,i.up)("BibtexBibliography");return(0,i.wg)(),(0,i.iD)("div",r,[(0,i._)("article",null,[(0,i._)("section",null,[s,(0,i._)("p",null,[(0,i.Wm)(de,null,{default:(0,i.w5)((()=>[l,c,d,u,h,p,(0,i.Wm)(ce,{name:"location_on"}),m,g,f,(0,i.Wm)(ce,{name:"fa-solid fa-envelope"}),y,b,(0,i._)("span",w,[(0,i.Wm)(ce,{name:"fa-brands fa-orcid"}),v,C]),k,(0,i._)("span",S,[(0,i.Wm)(ce,{name:"fa-solid fa-graduation-cap"}),A,P]),T])),_:1}),N,D,(0,i._)("small",null,[x,E,M,I,(0,i.Wm)(ce,{name:"fa-solid fa-envelope"}),H,(0,i.Wm)(ce,{name:"fa-solid fa-envelope"}),L,R,(0,i.Wm)(ce,{name:"location_on"}),B,_,(0,i._)("span",W,[(0,i.Wm)(ce,{name:"fa-brands fa-orcid"}),G,z]),F,(0,i._)("span",j,[(0,i.Wm)(ce,{name:"fa-solid fa-graduation-cap"}),J,U]),K])])]),q,(0,i._)("section",null,[O,X,(0,i._)("p",Z,[(0,i.Wm)(ue,{bibtex:e.journals},null,8,["bibtex"])]),Y,(0,i._)("p",V,[(0,i.Wm)(ue,{bibtex:e.conferences_int},null,8,["bibtex"])]),Q,(0,i._)("p",$,[(0,i.Wm)(ue,{bibtex:e.workshops},null,8,["bibtex"])]),ee,(0,i._)("p",ae,[(0,i.Wm)(ue,{bibtex:e.pub_short},null,8,["bibtex"])]),ne,(0,i._)("p",ie,[(0,i.Wm)(ue,{bibtex:e.conferences_nat},null,8,["bibtex"])]),te,(0,i._)("p",oe,[(0,i.Wm)(ue,{bibtex:e.reports},null,8,["bibtex"])]),re,(0,i._)("p",se,[(0,i.Wm)(ue,{bibtex:e.preprints},null,8,["bibtex"])])])])])}var ce=n(499),de=n(7121).Z,ue=n(8517).Z,he=n(6699).Z,pe=n(8676).Z,me=n(7121).Z,ge=n(6647).Z,fe=n(7991).Z;console.log(ge);const ye=(0,i.aZ)({name:"IndexPage",components:{},setup(){const e=(0,ce.iH)(de),a=(0,ce.iH)(ue),n=(0,ce.iH)(he),i=(0,ce.iH)(pe),t=(0,ce.iH)(me),o=(0,ce.iH)(ge),r=(0,ce.iH)(fe);return{journals:e,preprints:a,conferences_int:n,conferences_nat:i,pub_short:t,workshops:o,reports:r}}});var be=n(1639),we=n(2857),ve=n(9984),Ce=n.n(ve);const ke=(0,be.Z)(ye,[["render",le]]),Se=ke;Ce()(ye,"components",{QIcon:we.Z})},7121:(e,a,n)=>{"use strict";n.d(a,{Z:()=>i});const i="@article{caino-loresApplyingBigData2020,\n  title = {Applying Big Data Paradigms to a Large Scale Scientific Workflow: {{Lessons}} Learned and Future Directions},\n  shorttitle = {Applying Big Data Paradigms to a Large Scale Scientific Workflow},\n  author = {{Caino-Lores}, S. and Lapin, A. and Carretero, J. and Kropf, P.},\n  year = {2020},\n  month = sep,\n  journal = {Future Generation Computer Systems},\n  volume = {110},\n  pages = {440--452},\n  issn = {0167-739X},\n  doi = {10.1016/j.future.2018.04.014},\n  url = {https://www.sciencedirect.com/science/article/pii/S0167739X16308214},\n  urldate = {2023-03-08},\n  abstract = {The increasing amounts of data related to the execution of scientific workflows has raised awareness of their shift towards parallel data-intensive problems. In this paper, we deliver our experience combining the traditional high-performance computing and grid-based approaches with Big Data analytics paradigms, in the context of scientific ensemble workflows. Our goal was to assess and discuss the suitability of such data-oriented mechanisms for production-ready workflows, especially in terms of scalability. We focused on two key elements in the Big Data ecosystem: the data-centric programming model, and the underlying infrastructure that integrates storage and computation in each node. We experimented with a representative MPI-based iterative workflow from the hydrology domain, EnKF-HGS, which we re-implemented using the Spark data analysis framework. We conducted experiments on a local cluster, a private cloud running OpenNebula, and the Amazon Elastic Compute Cloud (AmazonEC2). The results we obtained were analysed to synthesize the lessons we learned from this experience, while discussing promising directions for further research.},\n  langid = {english},\n  keywords = {Apache spark,Big data,Cloud computing,Hydrology,Scientific workflows}\n}\n\n@article{caino-loresCloudificationMethodologyMultidimensional2015a,\n  title = {A Cloudification Methodology for Multidimensional Analysis: {{Implementation}} and Application to a Railway Power Simulator},\n  shorttitle = {A Cloudification Methodology for Multidimensional Analysis},\n  author = {{Caino-Lores}, Silvina and Fern{\\'a}ndez, Alberto Garc{\\'i}a and {Garc{\\'i}a-Carballeira}, F{\\'e}lix and P{\\'e}rez, Jes{\\'u}s Carretero},\n  year = {2015},\n  month = jun,\n  journal = {Simulation Modelling Practice and Theory},\n  volume = {55},\n  pages = {46--62},\n  issn = {1569-190X},\n  doi = {10.1016/j.simpat.2015.04.002},\n  url = {https://www.sciencedirect.com/science/article/pii/S1569190X15000611},\n  urldate = {2023-03-08},\n  abstract = {Many scientific areas make extensive use of computer simulations to study complex real-world processes. These computations are typically very resource-intensive and present scalability issues as experiments get larger even in dedicated clusters, since these are limited by their own hardware resources. Cloud computing raises as an option to move forward into the ideal unlimited scalability by providing virtually infinite resources, yet applications must be adapted to this new paradigm. This process of converting and/or migrating an application and its data in order to make use of cloud computing is sometimes known as cloudifying the application. We propose a generalist cloudification method based in the MapReduce paradigm to migrate scientific simulations into the cloud to provide greater scalability. We analysed its viability by applying it to a real-world railway power consumption simulatior and running the resulting implementation on Hadoop YARN over Amazon EC2. Our tests show that the cloudified application is highly scalable and there is still a large margin to improve the theoretical model and its implementations, and also to extend it to a wider range of simulations. We also propose and evaluate a multidimensional analysis tool based on the cloudified application. It generates, executes and evaluates several experiments in parallel, for the same simulation kernel. The results we obtained indicate that out methodology is suitable for resource intensive simulations and multidimensional analysis, as it improves infrastructure's utilization, efficiency and scalability when running many complex experiments.},\n  langid = {english},\n  keywords = {Cloud computing,Many-task computing,MapReduce,Migration,Railway simulator}\n}\n\n@article{caino-loresEfficientDesignAssessment2017,\n  title = {Efficient Design Assessment in the Railway Electric Infrastructure Domain Using Cloud Computing},\n  author = {{Ca{\\'i}no-Lores}, Silvina and Garc{\\'i}a, Alberto and {Garc{\\'i}a-Carballeira}, F{\\'e}lix and Carretero, Jes{\\'u}s},\n  year = {2017},\n  month = jan,\n  journal = {Integrated Computer-Aided Engineering},\n  volume = {24},\n  number = {1},\n  pages = {57--72},\n  publisher = {{IOS Press}},\n  issn = {1069-2509},\n  doi = {10.3233/ICA-160532},\n  url = {https://content.iospress.com/articles/integrated-computer-aided-engineering/ica532},\n  urldate = {2023-03-08},\n  abstract = {Nowadays, railway infrastructure designers rely heavily on computer simulators and expert systems to model, analyze and evaluate potential deployments prior to their installation. This paper presents the railway power consumption simulator model (RPC},\n  langid = {english}\n}\n\n@article{caino-loresHighPerformanceComputingBig2019,\n  title = {Toward {{High-Performance Computing}} and {{Big Data Analytics Convergence}}: {{The Case}} of {{Spark-DIY}}},\n  shorttitle = {Toward {{High-Performance Computing}} and {{Big Data Analytics Convergence}}},\n  author = {{Caino-Lores}, Silvina and Carretero, Jes{\\'u}s and Nicolae, Bogdan and Yildiz, Orcun and Peterka, Tom},\n  year = {2019},\n  journal = {IEEE Access},\n  volume = {7},\n  pages = {156929--156955},\n  issn = {2169-3536},\n  doi = {10.1109/ACCESS.2019.2949836},\n  abstract = {Convergence between high-performance computing (HPC) and big data analytics (BDA) is currently an established research area that has spawned new opportunities for unifying the platform layer and data abstractions in these ecosystems. This work presents an architectural model that enables the interoperability of established BDA and HPC execution models, reflecting the key design features that interest both the HPC and BDA communities, and including an abstract data collection and operational model that generates a unified interface for hybrid applications. This architecture can be implemented in different ways depending on the process- and data-centric platforms of choice and the mechanisms put in place to effectively meet the requirements of the architecture. The Spark-DIY platform is introduced in the paper as a prototype implementation of the architecture proposed. It preserves the interfaces and execution environment of the popular BDA platform Apache Spark, making it compatible with any Spark-based application and tool, while providing efficient communication and kernel execution via DIY, a powerful communication pattern library built on top of MPI. Later, Spark-DIY is analyzed in terms of performance by building a representative use case from the hydrogeology domain, EnKF-HGS. This application is a clear example of how current HPC simulations are evolving toward hybrid HPC-BDA applications, integrating HPC simulations within a BDA environment.},\n  keywords = {Analytical models,Big Data,Big data analytics,Business,Computer architecture,Convergence,Data models,Data visualization,DIY,high performance computing,MPI,spark}\n}\n\n@article{caino-loresSurveyDataCentricDataAware2016,\n  title = {A {{Survey}} on {{Data-Centric}} and {{Data-Aware Techniques}} for {{Large Scale Infrastructures}}},\n  author = {{Caino-Lores}, Silvina and Carretero, J.},\n  year = {2016},\n  month = feb,\n  journal = {International Journal of Computer and Information Engineering},\n  doi = {10.5281/zenodo.1112258},\n  url = {https://www.semanticscholar.org/paper/A-Survey-on-Data-Centric-and-Data-Aware-Techniques-Ca%C3%ADno-Lores-Carretero/9905b6cdc281dced8d9a25375cac542453e38ef3},\n  urldate = {2023-03-08},\n  abstract = {Large scale computing infrastructures have been widely developed with the core objective of providing a suitable platform for high-performance and high-throughput computing. These systems are designed to support resource-intensive and complex applications, which can be found in many scientific and industrial areas. Currently, large scale data-intensive applications are hindered by the high latencies that result from the access to vastly distributed data. Recent works have suggested that improving data locality is key to move towards exascale infrastructures efficiently, as solutions to this problem aim to reduce the bandwidth consumed in data transfers, and the overheads that arise from them. There are several techniques that attempt to move computations closer to the data. In this survey we analyse the different mechanisms that have been proposed to provide data locality for large scale high-performance and high-throughput systems. This survey intends to assist scientific computing community in understanding the various technical aspects and strategies that have been reported in recent literature regarding data locality. As a result, we present an overview of locality-oriented techniques, which are grouped in four main categories: application development, task scheduling, in-memory computing and storage platforms. Finally, the authors include a discussion on future research lines and synergies among the former techniques. Keywords\\textemdash{} Co-scheduling, data-centric, data-intensive, data locality, in-memory storage, large scale.},\n  note = {[TLDR] This survey analyses the different mechanisms that have been proposed to provide data locality for large scale high-performance and high-throughput systems, and presents an overview of locality-oriented techniques, which are grouped in four main categories: application development, task scheduling, in-memory computing and storage platforms.}\n}\n\n@article{doLightweightMethodEvaluating2021,\n  title = {A Lightweight Method for Evaluating in Situ Workflow Efficiency},\n  author = {Do, Tu Mai Anh and Pottier, Lo{\\\"i}c and {Caino-Lores}, Silvina and {Ferreira da Silva}, Rafael and Cuendet, Michel A. and Weinstein, Harel and Estrada, Trilce and Taufer, Michela and Deelman, Ewa},\n  year = {2021},\n  month = jan,\n  journal = {Journal of Computational Science},\n  volume = {48},\n  pages = {101259},\n  issn = {1877-7503},\n  doi = {10.1016/j.jocs.2020.101259},\n  url = {https://www.sciencedirect.com/science/article/pii/S1877750320305573},\n  urldate = {2023-03-08},\n  abstract = {Performance evaluation is crucial to understanding the behavior of scientific workflows. In this study, we target an emerging type of workflow, called in situ workflows. These workflows tightly couple components such as simulation and analysis to improve overall workflow performance. To understand the tradeoffs of various configurable parameters for coupling these heterogeneous tasks, namely simulation stride, and component placement, separately monitoring each component is insufficient to gain insights into the entire workflow behavior. Through an analysis of the state-of-the-art research, we propose a lightweight metric, derived from a defined in situ step, for assessing resource usage efficiency of an in situ workflow execution. By applying this metric to a synthetic workflow, which is parameterized to emulate behaviors of a molecular dynamics simulation, we explore two possible scenarios (Idle Simulation and Idle Analyzer) for the characterization of in situ workflow execution. In addition to preliminary results from a recently published study [11], we further exploit the proposed metric to evaluate a practical in situ workflow with a real molecular dynamics application, i.e., GROMACS. Experimental results show that the in transit placement (analytics on dedicated nodes) sustains a higher frequency for performing in situ analysis compared to the helper-core configuration (analytics co-allocated with simulation).},\n  langid = {english},\n  keywords = {High-performance computing,model,Molecular dynamics,Scientific workflow}\n}\n\n@article{doPerformanceAssessmentEnsembles2022,\n  title = {Performance Assessment of Ensembles of in Situ Workflows under Resource Constraints},\n  author = {Do, Tu Mai Anh and Pottier, Lo{\\\"i}c and {Ferreira da Silva}, Rafael and {Caino-Lores}, Silvina and Taufer, Michela and Deelman, Ewa},\n  year = {2022},\n  journal = {Concurrency and Computation: Practice and Experience},\n  volume = {n/a},\n  number = {n/a},\n  pages = {e7111},\n  issn = {1532-0634},\n  doi = {10.1002/cpe.7111},\n  url = {https://onlinelibrary.wiley.com/doi/abs/10.1002/cpe.7111},\n  urldate = {2023-03-08},\n  abstract = {Scientific breakthroughs in biomolecular methods and improvements in hardware technology have shifted from a long-running simulation to a large set of shorter simulations running simultaneously, called an ensemble. In an ensemble, simulations are usually coupled with analyses of data produced by the simulations. In situ methods can be used to analyze large volumes of data generated by scientific simulations at runtime (i.e., simulations and analyses are performed concurrently). In this work, we study the execution of ensemble-based simulations paired with in situ analyses using in-memory staging methods. Using an ensemble of molecular dynamics in situ workflows with multiple simulations and analyses, we first show that collecting traditional metrics such as makespan, instructions per cycle, memory usage, or cache miss ratio is not sufficient to characterize complex behaviors of ensembles. We propose a method to evaluate the performance of ensembles of workflows that captures multiple resource usage aspects: resource efficiency, resource allocation, and resource provisioning. Experimental results demonstrate that the proposed method can effectively distinguish the performance of different component placements in an ensemble with up to 32 ensemble members. By evaluating different co-location scenarios, our proposed performance indicators demonstrate benefits of co-locating simulation and coupled analyses within a compute node.},\n  langid = {english},\n  keywords = {ensemble workflow,high-performance computing,in situ model,molecular dynamics,scientific workflow}\n}\n\n@article{herbeinAnalyticalPerformanceModel2022a,\n  title = {An Analytical Performance Model of Generalized Hierarchical Scheduling},\n  author = {Herbein, Stephen and Patki, Tapasya and Ahn, Dong H and Mobo, Sebastian and Hathaway, Clark and {Caino-Lores}, Silvina and Corbett, James and Domyancic, David and Scogland, Thomas RW and {de Supinski}, Bronis R and Taufer, Michela},\n  year = {2022},\n  month = may,\n  journal = {The International Journal of High Performance Computing Applications},\n  volume = {36},\n  number = {3},\n  pages = {289--306},\n  publisher = {{SAGE Publications Ltd STM}},\n  issn = {1094-3420},\n  doi = {10.1177/10943420211051039},\n  url = {https://doi.org/10.1177/10943420211051039},\n  urldate = {2023-03-08},\n  abstract = {High performance computing (HPC) workflows are undergoing tumultuous changes, including an explosion in size and complexity. Despite these changes, most batch job systems still use slow, centralized schedulers. Generalized hierarchical scheduling (GHS) solves many of the challenges that face modern workflows, but GHS has not been widely adopted in HPC. A major difficulty that hinders adoption is the lack of a performance model to aid in configuring GHS for optimal performance on a given application. We propose an analytical performance model of GHS, and we validate our proposed model with four different applications on a moderately-sized system. Our validation shows that our model is extremely accurate at predicting the performance of GHS, explaining 98.7\\% of the variance (i.e., an R2 statistic of 0.987). Our results also support the claim that GHS overcomes scheduling throughput problems; we measured throughput improvements of up to 270? on our moderately-sized system. We then apply our performance model to a pre-exascale system, where our model predicts throughput improvements of four orders of magnitude and provides insight into optimally configuring GHS on next generation systems.},\n  langid = {english}\n}\n\n@article{kellerrorabaughBuildingHighThroughputNeural2022,\n  title = {Building {{High-Throughput Neural Architecture Search Workflows}} via a {{Decoupled Fitness Prediction Engine}}},\n  author = {Keller Rorabaugh, Ariel and {Caino-Lores}, Silvina and Johnston, Travis and Taufer, Michela},\n  year = {2022},\n  month = nov,\n  journal = {IEEE Transactions on Parallel and Distributed Systems},\n  volume = {33},\n  number = {11},\n  pages = {2913--2926},\n  issn = {1558-2183},\n  doi = {10.1109/TPDS.2022.3140681},\n  abstract = {Neural networks (NN) are used in high-performance computing and high-throughput analysis to extract knowledge from datasets. Neural architecture search (NAS) automates NN design by generating, training, and analyzing thousands of NNs. However, NAS requires massive computational power for NN training. To address challenges of efficiency and scalability, we propose PENGUIN, a decoupled fitness prediction engine that informs the search without interfering in it. PENGUIN uses parametric modeling to predict fitness of NNs. Existing NAS methods and parametric modeling functions can be plugged into PENGUIN to build flexible NAS workflows. Through this decoupling and flexible parametric modeling, PENGUIN reduces training costs: it predicts the fitness of NNs, enabling NAS to terminate training NNs early. Early termination increases the number of NNs that fixed compute resources can evaluate, thus giving NAS additional opportunity to find better NNs. We assess the effectiveness of our engine on 6,000 NNs across three diverse benchmark datasets and three state of the art NAS implementations using the Summit supercomputer. Augmenting these NAS implementations with PENGUIN can increase throughput by a factor of 1.6 to 7.1. Furthermore, walltime tests indicate that PENGUIN can reduce training time by a factor of 2.5 to 5.3.},\n  keywords = {artificial intelligence,Artificial neural networks,Data models,Engines,Machine learning,neural networks,Parametric statistics,performance prediction,Predictive models,Search problems,Training}\n}\n\n@article{rorabaughHighFrequencyAccuracy2022,\n  title = {High Frequency Accuracy and Loss Data of Random Neural Networks Trained on Image Datasets},\n  author = {Rorabaugh, Ariel Keller and {Ca{\\'i}no-Lores}, Silvina and Johnston, Travis and Taufer, Michela},\n  year = {2022},\n  month = feb,\n  journal = {Data in Brief},\n  volume = {40},\n  pages = {107780},\n  issn = {2352-3409},\n  doi = {10.1016/j.dib.2021.107780},\n  url = {https://www.sciencedirect.com/science/article/pii/S2352340921010544},\n  urldate = {2023-03-08},\n  abstract = {Neural Networks (NNs) are increasingly used across scientific domains to extract knowledge from experimental or computational data. An NN is composed of natural or artificial neurons that serve as simple processing units and are interconnected into a model architecture; it acquires knowledge from the environment through a learning process and stores this knowledge in its connections. The learning process is conducted by training. During NN training, the learning process can be tracked by periodically validating the NN and calculating its fitness. The resulting sequence of fitness values (i.e., validation accuracy or validation loss) is called the NN learning curve. The development of tools for NN design requires knowledge of diverse NNs and their complete learning curves. Generally, only final fully-trained fitness values for highly accurate NNs are made available to the community, hampering efforts to develop tools for NN design and leaving unaddressed aspects such as explaining the generation of an NN and reproducing its learning process. Our dataset fills this gap by fully recording the structure, metadata, and complete learning curves for a wide variety of random NNs throughout their training. Our dataset captures the lifespan of 6000 NNs throughout generation, training, and validation stages. It consists of a suite of 6000 tables, each table representing the lifespan of one NN. We generate each NN with randomized parameter values and train it for 40 epochs on one of three diverse image datasets (i.e., CIFAR-100, FashionMNIST, SVHN). We calculate and record each NN's fitness with high frequency\\textemdash every half epoch\\textemdash to capture the evolution of the training and validation process. As a result, for each NN, we record the generated parameter values describing the structure of that NN, the image dataset on which the NN trained, and all loss and accuracy values for the NN every half epoch. We put our dataset to the service of researchers studying NN performance and its evolution throughout training and validation. Statistical methods can be applied to our dataset to analyze the shape of learning curves in diverse NNs, and the relationship between an NN's structure and its fitness. Additionally, the structural data and metadata that we record enable the reconstruction and reproducibility of the associated NN.},\n  langid = {english},\n  keywords = {Accuracy curve,Artificial intelligence,Classification,Early stopping,Loss curve,Machine learning,Neural architecture search,Performance prediction}\n}\n"},8517:(e,a,n)=>{"use strict";n.d(a,{Z:()=>i});const i="@inproceedings{caino2023_pasc,\n  title = {Runtime Monitoring of Molecular Dynamics Simulations through in Situ Analysis and Annotation of Collective Variables},\n  booktitle = {Platform for Advanced Scientific Computing Conference ({{PASC}})},\n  author = {{Caino-Lores, S.} and Cuendet, M. and Marquez, J. and Kots, E. and Estrada, T. and Deelman, E. and Weinstein, H. and Taufer, M.},\n  year = {2023},\n  note = {\\emph{Under review.}}\n}\n\n@inproceedings{caino2023_pasc,\n  title = {Runtime Monitoring of Molecular Dynamics Simulations through in Situ Analysis and Annotation of Collective Variables},\n  booktitle = {Platform for Advanced Scientific Computing Conference ({{PASC}})},\n  author = {{Caino-Lores, Silvina} and Cuendet, M. and Marquez, J. and Kots, E. and Estrada, T. and Deelman, E. and Weinstein, H. and Taufer, M.},\n  year = {2023},\n  note = {\\emph{Under review.}}\n}\n\n@misc{patelReproducibilityFirstImage2022a,\n  title = {Reproducibility of the {{First Image}} of a {{Black Hole}} in the {{Galaxy M87}} from the {{Event Horizon Telescope}} ({{EHT}}) {{Collaboration}}},\n  author = {Patel, Ria and Roachell, Brandan and {Caino-Lores}, Silvina and Ketron, Ross and Leonard, Jacob and Tan, Nigel and Brown, Duncan and Deelman, Ewa and Taufer, Michela},\n  year = {2022},\n  month = may,\n  number = {arXiv:2205.10267},\n  eprint = {arXiv:2205.10267},\n  publisher = {{arXiv}},\n  doi = {10.48550/arXiv.2205.10267},\n  url = {http://arxiv.org/abs/2205.10267},\n  urldate = {2023-03-08},\n  abstract = {This paper presents an interdisciplinary effort aiming to develop and share sustainable knowledge necessary to analyze, understand, and use published scientific results to advance reproducibility in multi-messenger astrophysics. Specifically, we target the breakthrough work associated with the generation of the first image of a black hole, called M87. The image was computed by the Event Horizon Telescope Collaboration. Based on the artifacts made available by EHT, we deliver documentation, code, and a computational environment to reproduce the first image of a black hole. Our deliverables support new discovery in multi-messenger astrophysics by providing all the necessary tools for generalizing methods and findings from the EHT use case. Challenges encountered during the reproducibility of EHT results are reported. The result of our effort is an open-source, containerized software package that enables the public to reproduce the first image of a black hole in the galaxy M87.},\n  archiveprefix = {arxiv},\n  keywords = {Astrophysics - High Energy Astrophysical Phenomena,Astrophysics - Instrumentation and Methods for Astrophysics,Computer Science - Distributed; Parallel; and Cluster Computing,General Relativity and Quantum Cosmology}\n}\n"},6699:(e,a,n)=>{"use strict";n.d(a,{Z:()=>i});const i="@inproceedings{caino-loresDataAwareSupportHybrid2017,\n  title = {Data-{{Aware Support}} for {{Hybrid HPC}} and {{Big Data Applications}}},\n  booktitle = {2017 17th {{IEEE}}/{{ACM International Symposium}} on {{Cluster}}, {{Cloud}} and {{Grid Computing}} ({{CCGRID}})},\n  author = {{Caino-Lores}, Silvina and Isaila, Florin and Carretero, Jes{\\'u}s},\n  year = {2017},\n  month = may,\n  pages = {719--722},\n  doi = {10.1109/CCGRID.2017.55},\n  abstract = {Nowadays there is a raising interest in bridging the gap between Big Data application models and data-intensive HPC. This work explores the effects that Big Data-inspired paradigms could have in current scientific applications through the evaluation of a real-world application from the hydrology domain. This evaluation led to experience that portrayed the key aspects of the HPC and Big Data paradigms that made them successful in their respective worlds. With this information, we established a research roadmap to build a platform suitable for HPC hybrid applications, with a focus on efficient data management and fault-tolerance.},\n  keywords = {big data,Cloud computing,Computational modeling,Data analysis,data management,data-intensive computing,high-performance computing,Hydrology,Random access memory,Scalability,scientific computing,Sparks}\n}\n\n@inproceedings{caino-loresMethodologicalApproachDataCentric2016,\n  title = {Methodological {{Approach}} to {{Data-Centric Cloudification}} of {{Scientific Iterative Workflows}}},\n  booktitle = {International {{Conference}} on {{Algorithms}} and {{Architectures}} for {{Parallel Processing}}},\n  author = {{Ca{\\'i}no-Lores}, Silvina and Lapin, Andrei and Kropf, Peter and Carretero, Jes{\\'u}s},\n  editor = {Carretero, Jesus and {Garcia-Blas}, Javier and Ko, Ryan K.L. and Mueller, Peter and Nakano, Koji},\n  year = {2016},\n  series = {Lecture {{Notes}} in {{Computer Science}}},\n  pages = {469--482},\n  publisher = {{Springer International Publishing}},\n  address = {{Cham}},\n  doi = {10.1007/978-3-319-49583-5_36},\n  abstract = {The computational complexity and the constantly increasing amount of input data for scientific computing models is threatening their scalability. In addition, this is leading towards more data-intensive scientific computing, thus rising the need to combine techniques and infrastructures from the HPC and big data worlds. This paper presents a methodological approach to cloudify generalist iterative scientific workflows, with a focus on improving data locality and preserving performance. To evaluate this methodology, it was applied to an hydrological simulator, EnKF-HGS. The design was implemented using Apache Spark, and assessed in a local cluster and in Amazon Elastic Compute Cloud (EC2) against the original version to evaluate performance and scalability.},\n  isbn = {978-3-319-49583-5},\n  langid = {english},\n  keywords = {Apache spark,Cloud computing,Cloudification,Ensemble Kalman filter,HydroGeoSphere,Hydrology,Iterative workflows,Map reduce}\n}\n\n@inproceedings{caino-loresSparkDIYFrameworkInteroperable2018,\n  title = {Spark-{{DIY}}: {{A Framework}} for {{Interoperable Spark Operations}} with {{High Performance Block-Based Data Models}}},\n  shorttitle = {Spark-{{DIY}}},\n  booktitle = {2018 {{IEEE}}/{{ACM}} 5th {{International Conference}} on {{Big Data Computing Applications}} and {{Technologies}} ({{BDCAT}})},\n  author = {{Ca{\\'i}no-Lores}, Silvina and Carretero, Jes{\\'u}s and Nicolae, Bogdan and Yildiz, Orcun and Peterka, Tom},\n  year = {2018},\n  month = dec,\n  pages = {1--10},\n  doi = {10.1109/BDCAT.2018.00010},\n  abstract = {Today's scientific applications are increasingly relying on a variety of data sources, storage facilities, and computing infrastructures, and there is a growing demand for data analysis and visualization for these applications. In this context, exploiting Big Data frameworks for scientific computing is an opportunity to incorporate high-level libraries, platforms, and algorithms for machine learning, graph processing, and streaming; inherit their data awareness and fault-tolerance; and increase productivity. Nevertheless, limitations exist when Big Data platforms are integrated with an HPC environment, namely poor scalability, severe memory overhead, and huge development effort. This paper focuses on a popular Big Data framework -Apache Spark- and proposes an architecture to support the integration of highly scalable MPI block-based data models and communication patterns with a map-reduce-based programming model. The resulting platform preserves the data abstraction and programming interface of Spark, without conducting any changes in the framework, but allows the user to delegate operations to the MPI layer. The evaluation of our prototype shows that our approach integrates Spark and MPI efficiently at scale, so end users can take advantage of the productivity facilitated by the rich ecosystem of high-level Big Data tools and libraries based on Spark, without compromising efficiency and scalability.},\n  keywords = {Adaptation models,Big Data,Data models,HPC; Big Data; Spark; MPI; High-Performance analytics; programming environments,Libraries,Programming,Sparks,Tools}\n}\n\n@inproceedings{carreteroMultiObjectiveSimulatorOptimal2015a,\n  title = {A {{Multi-Objective Simulator}} for {{Optimal Power Dimensioning}} on {{Electric Railways}} Using {{Cloud Computing}}},\n  booktitle = {International {{Conference}} on {{Simulation}} and {{Modeling Methodologies}}, {{Technologies}} and {{Applications}}},\n  author = {Carretero, Jesus and Caino, Silvina and {Garcia-Carballeira}, Felix and Garcia, Alberto},\n  year = {2015},\n  month = jul,\n  volume = {2},\n  pages = {428--438},\n  publisher = {{SCITEPRESS}},\n  doi = {10.5220/0005573404280438},\n  url = {https://www.scitepress.org/PublishedPapers/2015/55734},\n  urldate = {2023-03-08},\n  abstract = {Power dimensioning and energy saving have been traditionally two main issues regarding the deployment of electric grids. Electric railways are also concerned about these issues, and simulators have been traditionally used to test such infrastructure deployments. The main goal of this paper is to present the Railway electric Power Consumption Simulator, a simulation model and tool for the railway energy provisioning problem. This simulator aims to propose electric railway infrastructure deployments, optimizing the quality of the electric flow supplied to train, as well as saving as much energy as possible. The paper describes the simulator structure, as well as the ontology used to translate railway infrastructure elements into an electric circuit. Because these two objectives are conflicting, a multi-objective optimization problem is formulated and solved. Finally, a standard railway scenario is used to illustrate the capabilities of the tool, trying to find the best electric substation placements in order to optimize such objectives. The evaluation shows how the tool can handle hundreds of simulated scenarios using Cloud Computing techniques.},\n  isbn = {978-989-758-120-5},\n  langid = {english}\n}\n\n@inproceedings{olayaIdentifyingStructuralProperties2022a,\n  title = {Identifying {{Structural Properties}} of {{Proteins}} from {{X-ray Free Electron Laser Diffraction Patterns}}},\n  booktitle = {2022 {{IEEE}} 18th {{International Conference}} on E-{{Science}} (e-{{Science}})},\n  author = {Olaya, Paula and {Ca{\\'i}no-Lores}, Silvina and Lama, Vanessa and Patel, Ria and Rorabaugh, Ariel Keller and Miyashita, Osamu and Tama, Florence and Taufer, Michela},\n  year = {2022},\n  month = oct,\n  pages = {21--31},\n  doi = {10.1109/eScience55777.2022.00017},\n  abstract = {Capturing structural information of a biological molecule is crucial to determine its function and understand its mechanics. X-ray Free Electron Lasers (XFEL) are an experimental method used to create diffraction patterns (images) that can reveal structural information. In this work we design, implement, and evaluate XPSI (X-ray Free Electron Laser-based Protein Structure Identifier), a framework capable of predicting three structural properties in molecules (i.e., orientation, conformation, and protein type) from their diffraction patterns. XPSI predicts these properties with high accuracy in challenging scenarios, such as recognizing orientations despite symmetries in diffraction patterns, distinguishing conformations even when they have similar structures, and identifying protein types under different noise conditions. Our framework shows low computational cost and high prediction accuracy compared to other machine learning methods such as random forest and neural networks.},\n  keywords = {autoencoder,Diffraction,diffraction patterns,Free electron lasers,Laser beams,machine learning,proteins,Proteins,Task analysis,X-ray diffraction,X-ray lasers}\n}\n"},8676:(e,a,n)=>{"use strict";n.d(a,{Z:()=>i});const i="@misc{caino2014_sarteco,\n  title = {Breaking Data Dependences in Numerical Simulations Using Map-Reduce},\n  author = {{Caino-Lores, Silvina} and Garc{\\'i}a, Alberto and {Garc{\\'i}a-Carballeira}, F{\\'e}lix and Carretero, Jes{\\'u}s},\n  year = {2014},\n  month = sep,\n  journal = {25th SARTECO parallelism meeting},\n  address = {{Valladolid, Spain}}\n}\n\n@misc{caino2016_sarteco,\n  title = {Cloudification of a Legacy Hydrological Simulator Using Apache Spark},\n  author = {{Caino-Lores, Silvina} and Lapin, Andrei and Kropf, Peter and Carretero, Jes{\\'u}s},\n  year = {2016},\n  month = sep,\n  journal = {27th SARTECO parallelism meeting},\n  address = {{Salamanca, Spain}}\n}\n"},6647:(e,a,n)=>{"use strict";n.d(a,{Z:()=>i});const i="@inproceedings{caino-loresCloudificationMethodologyNumerical2014,\n  title = {A {{Cloudification Methodology}} for {{Numerical Simulations}}},\n  booktitle = {Euro-{{Par}} 2014: {{Parallel Processing Workshops}}},\n  author = {{Caino-Lores}, Silvina and Garc{\\'i}a, Alberto and {Garc{\\'i}a-Carballeira}, F{\\'e}lix and Carretero, Jes{\\'u}s},\n  editor = {Lopes, Lu{\\'i}s and {\\v Z}ilinskas, Julius and Costan, Alexandru and Cascella, Roberto G. and Kecskemeti, Gabor and Jeannot, Emmanuel and Cannataro, Mario and Ricci, Laura and Benkner, Siegfried and Petit, Salvador and Scarano, Vittorio and Gracia, Jos{\\'e} and Hunold, Sascha and Scott, Stephen L. and Lankes, Stefan and Lengauer, Christian and Carretero, Jes{\\'u}s and Breitbart, Jens and Alexander, Michael},\n  year = {2014},\n  series = {Lecture {{Notes}} in {{Computer Science}}},\n  pages = {375--386},\n  publisher = {{Springer International Publishing}},\n  address = {{Cham}},\n  doi = {10.1007/978-3-319-14313-2_32},\n  abstract = {Many scientific areas make extensive use of computer simulations to study complex real-world processes. These computations are typically very resource-intensive and present scalability issues as experiments get larger, even in dedicated clusters since they are limited by their own hardware resources. Cloud computing raises as an option to move forward into the ideal unlimited scalability by providing virtually infinite resources, yet applications must be adapted to this new paradigm. We propose a generalist cloudification method based in the MapReduce paradigm to migrate numerical simulations into the cloud to provide greater scalability. We analysed its viability by applying it to a real-world simulation and running the resulting implementation on Hadoop YARN over Amazons EC2. Our tests show that the cloudified application is highly scalable and there is still a large margin to improve the theoretical model and its implementations, and also to extend it to a wider range of simulations.},\n  isbn = {978-3-319-14313-2},\n  langid = {english},\n  keywords = {Cloud Computing,Hadoop MapReduce,Kernel Execution,MapReduce Framework,Overhead Line}\n}\n\n@inproceedings{caino2016_works,\n  title = {Lessons Learned from Applying Big Data Paradigms to a Large Scale Scientific Workflow},\n  booktitle = {11th Workshop on Workflows in Support of Large-Scale Science ({{WORKS}} 2016)},\n  author = {{Caino-Lores, Silvina} and Lapin, Andrei and Kropf, Peter and Carretero, Jes{\\'u}s},\n  year = {2016},\n  month = nov,\n  address = {{Salt Lake City, Utah, USA}},\n  url = {https://ceur-ws.org/Vol-1800/short1.pdf}\n}\n\n@inproceedings{doAssessingResourceProvisioning2021,\n  title = {Assessing {{Resource Provisioning}} and {{Allocation}} of {{Ensembles}} of {{In Situ Workflows}}},\n  booktitle = {50th {{International Conference}} on {{Parallel Processing Workshop}}},\n  author = {Do, Tu Mai Anh and Pottier, Lo{\\\"i}c and {Ferreira da Silva}, Rafael and {Ca{\\'i}no-Lores}, Silvina and Taufer, Michela and Deelman, Ewa},\n  year = {2021},\n  month = sep,\n  series = {{{ICPP Workshops}} '21},\n  pages = {1--10},\n  publisher = {{Association for Computing Machinery}},\n  address = {{New York, NY, USA}},\n  doi = {10.1145/3458744.3474051},\n  url = {https://doi.org/10.1145/3458744.3474051},\n  urldate = {2023-03-08},\n  abstract = {Scientific breakthroughs in biomolecular methods and improvements in hardware technology have shifted from a single long-running simulation to a large set of shorter simulations running simultaneously, called an ensemble. In an ensemble, each independent simulation is usually coupled with several analyses that apply identical or distinct algorithms on data produced by the corresponding simulation. Today, In situ methods are used to analyze large volumes of data generated by scientific simulations at runtime. This work studies the execution of ensemble-based simulations paired with In situ analyses using in-memory staging methods. Because simulations and analyses forming an ensemble typically run concurrently, deploying an ensemble requires efficient co-location-aware strategies, making sure the data flow between simulations and analyses that form an In situ workflow is efficient. Using an ensemble of molecular dynamics In situ workflows with multiple simulations and analyses, we first show that collecting traditional metrics such as makespan, instructions per cycle, memory usage, or cache miss ratio is not sufficient to characterize the complex behaviors of ensembles. Thus, we propose a method to evaluate the performance of ensembles of workflows that captures resource usage (efficiency), resource allocation, and component placement. Experimental results demonstrate that our proposed method can effectively capture the performance of different component placements in an ensemble. By evaluating different co-location scenarios, our performance indicator demonstrates improvements of up to four orders of magnitude when co-locating simulation and coupled analyses within a single computational host.},\n  isbn = {978-1-4503-8441-4},\n  keywords = {Ensemble workflow,High-performance computing,In situ model,Molecular dynamics,Scientific workflow}\n}\n\n@inproceedings{luettgauReproducingExtendingAnalytical2022,\n  title = {Reproducing and {{Extending Analytical Performance Models}} of {{Generalized Hierarchical Scheduling}}},\n  booktitle = {2022 {{IEEE}} 18th {{International Conference}} on E-{{Science}} (e-{{Science}})},\n  author = {Luettgau, Jakob and {Caino-Lores}, Silvina and Suarez, Kae and Ahn, Dong H. and Herbein, Stephen and Taufer, Michela},\n  year = {2022},\n  month = oct,\n  pages = {450--455},\n  doi = {10.1109/eScience55777.2022.00081},\n  abstract = {Workflows in High-Performance Computing (HPC) are rapidly changing towards more complex and large-scale workflows. In particular, high-throughput and ensemble workflows are becoming increasingly common. These workflows impose significant burden on current HPC scheduling systems which typically use slow, centralized schedulers. Generalized hierarchical scheduling (GHS) is a potential solution to face modern workflows but is not widely adopted in HPC yet. One difficulty hindering widespread adoption is the lack of performance models to configure and fit application requirements. The few existing models are often built on stick assumptions that can substantially reduce the analysis realism. In this paper, we reproduce the analysis and improve the realism of a state-of-the-art model presented in ``An Analytical Performance Model of Generalized Hierarchical Scheduling'' [1] by Herbein and co-authors. Specifically, we first reproduce four key analysis studies in the original paper and then expand the model by removing key assumptions, one at a time. In doing so, we extend the realism of the original model. We empirically validate our extended model using three different scenarios and discuss the observed accuracy.},\n  keywords = {Adaptation models,Analytical models,Computational modeling,Ensemble workflows,Hierarchical scheduling,High performance computing,Performance modeling,Predictive models,Processor scheduling,Scalability,Workflow analysis}\n}\n"},7991:(e,a,n)=>{"use strict";n.d(a,{Z:()=>i});const i="@techreport{caino2017_report,\n  title = {Report on Application Adaptation and Deployment},\n  author = {{Caino-Lores, Silvina} and Serrano, Estefania and Garcia, Alberto and Sotomayor, Rafael and Sanchez, Luis Miguel},\n  year = {2017}\n}\n\n@techreport{caino2017technical,\n  title = {Technical Report on Techniques to Expose and Exploit Data Locality},\n  author = {{Caino-Lores, Silvina} and Duro, Francisco Jose Rodrigo and Garcia, Francisco Javier and Carretero, Jesus},\n  year = {2017},\n  url = {https://www.arcos.inf.uc3m.es/wp-content/uploads/sites/47/2017/02/wg4-E4.1-v1.0.pdf}\n}\n\n@techreport{caino2018_report,\n  title = {Report on Techniques for Data Management on Integrated {{HPC}} and {{Big Data}} Platforms},\n  author = {Carretero, Jesus and {Garcia-Carballeira}, Felix and Garcia, Francisco Javier and Isaila, Florin and {Caino-Lores}, Silvina and Serrano, Estefania},\n  year = {2018},\n  url = {https://www.arcos.inf.uc3m.es/bighpc/wp-content/uploads/sites/52/2018/09/d-2.2.pdf}\n}\n\n@article{dasilva2021_summit,\n  title = {Workflows Community Summit: {{Advancing}} the State- of-the-Art of Scientific Workflows Management Systems Research and Development},\n  author = {{Ferreira da Silva}, Rafael and Casanova, Henri and Chard, Kyle and Coleman, Tain{\\~a} and Laney, Dan and Ahn, Dong and Jha, Shantenu and Howell, Dorran and {Soiland-Reys}, Stian and Altintas, Ilkay and Thain, Douglas and Filgueira, Rosa and Babuji, Yadu and Badia, Rosa M. and Balis, Bartosz and {\\textbf{Caino-Lores, Silvina}} and Callaghan, Scott and Coppens, Frederik and Crusoe, Michael R. and De, Kaushik and Di Natale, Frank and Do, Tu M. A. and Enders, Bjoern and Fahringer, Thomas and Fouilloux, Anne and Fursin, Grigori and Gaignard, Alban and Ganose, Alex and Garijo, Daniel and Gesing, Sandra and Goble, Carole and Hasan, Adil and Huber, Sebastiaan and Katz, Daniel S. and Leser, Ulf and Lowe, Douglas and Ludaescher, Bertram and Maheshwari, Ketan and Malawski, Maciej and Mayani, Rajiv and Mehta, Kshitij and Merzky, Andre and Munson, Todd and Ozik, Jonathan and Pottier, Lo{\\\"i}c and Ristov, Sashko and Roozmeh, Mehdi and Souza, Renan and Suter, Fr{\\'e}d{\\'e}ric and Tovar, Benjamin and Turilli, Matteo and Vahi, Karan and {Vidal-Torreira}, Alvaro and Whitcup, Wendy and Wilde, Michael and Williams, Alan and Wolf, Matthew and Wozniak, Justin},\n  year = {2021},\n  month = jun,\n  doi = {10.5281/zenodo.4915801},\n  url = {https://doi.org/10.5281/zenodo.4915801}\n}\n"},9652:(e,a,n)=>{e.exports=n.p+"img/portrait.216df37a.jpg"}}]);